INSERT INTO program_variant_weeks (
    variant_id, week_number, phase, focus, workouts,
    program_name, variant_name, priority, has_supersets, description, category
) SELECT
    pv.id,
    1,
    'Single Session',
    'Week 1 - Build',
    '[{"workout_name": "Overhead Press Mobility", "type": "flexibility", "duration_minutes": 20, "exercises": [{"name": "Lacrosse Ball Pec Minor Release", "exercise_library_id": null, "in_library": false, "sets": 2, "reps": 1, "rest_seconds": 0, "weight_guidance": "60s each side", "equipment": "Lacrosse Ball", "body_part": "Chest", "primary_muscle": "Pectoralis Minor", "secondary_muscles": ["Anterior Deltoid"], "difficulty": "beginner", "form_cue": "Pin ball below collarbone, apply pressure", "substitution": "Foam Roll Chest"}, {"name": "Wall Slide", "exercise_library_id": null, "in_library": false, "sets": 2, "reps": 10, "rest_seconds": 0, "weight_guidance": "Slow tempo", "equipment": "Bodyweight", "body_part": "Shoulders", "primary_muscle": "Serratus Anterior", "secondary_muscles": ["Lower Trapezius"], "difficulty": "beginner", "form_cue": "Back flat on wall, slide arms up maintaining contact", "substitution": "Floor Slide"}, {"name": "Banded Shoulder Flexion", "exercise_library_id": null, "in_library": false, "sets": 2, "reps": 10, "rest_seconds": 0, "weight_guidance": "Light band", "equipment": "Resistance Band", "body_part": "Shoulders", "primary_muscle": "Deltoids", "secondary_muscles": ["Rotator Cuff"], "difficulty": "beginner", "form_cue": "Band anchored low, raise arms overhead with control", "substitution": "Dowel Overhead Press"}, {"name": "Thread the Needle", "exercise_library_id": null, "in_library": false, "sets": 2, "reps": 8, "rest_seconds": 0, "weight_guidance": "Each side", "equipment": "Bodyweight", "body_part": "Back", "primary_muscle": "Thoracic Spine", "secondary_muscles": ["Obliques"], "difficulty": "beginner", "form_cue": "Reach under and through, then open up to ceiling", "substitution": "Seated Thoracic Rotation"}, {"name": "PNF Overhead Stretch", "exercise_library_id": null, "in_library": false, "sets": 2, "reps": 3, "rest_seconds": 0, "weight_guidance": "Contract-relax each side", "equipment": "Bodyweight", "body_part": "Shoulders", "primary_muscle": "Latissimus Dorsi", "secondary_muscles": ["Teres Major"], "difficulty": "intermediate", "form_cue": "Contract 5s, relax and stretch deeper", "substitution": "Passive Overhead Stretch"}, {"name": "Bottoms-Up Kettlebell Hold", "exercise_library_id": null, "in_library": false, "sets": 2, "reps": 1, "rest_seconds": 0, "weight_guidance": "Hold 20s each side", "equipment": "Kettlebell", "body_part": "Shoulders", "primary_muscle": "Rotator Cuff", "secondary_muscles": ["Deltoids", "Forearms"], "difficulty": "intermediate", "form_cue": "Light KB, maintain vertical alignment", "substitution": "Banded Overhead Hold"}]}]'::jsonb,
    'Overhead Press Mobility',
    'Overhead Press Mobility - 1w 3x/wk',
    'High',
    false,
    'Shoulder mobility for overhead pressing including lat, thoracic, and rotator cuff drills',
    'Lift Mobility'
FROM program_variants pv
JOIN branded_programs bp ON bp.id = pv.base_program_id
WHERE bp.name = 'Overhead Press Mobility'
  AND pv.duration_weeks = 1
  AND pv.sessions_per_week = 3
ON CONFLICT DO NOTHING;

